import{_ as e,a as o,b as a,c as d,d as r}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as i}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as s,o as c,c as n,a2 as l}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"ps/Other/ocr.md","filePath":"ps/Other/ocr.md","lastUpdated":1781962217000}'),p={name:"ps/Other/ocr.md"};function u(h,t,g,m,b,y){return c(),n("div",null,[...t[0]||(t[0]=[l('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR له images، scans او document screenshots څخه text استخراجوي.</p><p>له recognition وروسته result copy کولای شئ، یا یې د <code>Markdown</code>، <code>PDF</code> یا <code>Word</code> په توګه export کولای شئ، او څو formats یو ځای package او download کولای شئ.</p><h2 id="ocr-څه-کولای-شي" tabindex="-1">OCR څه کولای شي <a class="header-anchor" href="#ocr-څه-کولای-شي" aria-label="Permalink to &quot;OCR څه کولای شي&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>تشریح</th></tr></thead><tbody><tr><td>Image text recognition</td><td>له images، screenshots او scans څخه text استخراجوي.</td></tr><tr><td>Document layout recognition</td><td>د tables، formulas، stamps او ګډ text-image layouts لپاره ښه دی.</td></tr><tr><td>Multiple services</td><td>Baidu PaddleOCR، Microsoft Azure Vision او Google Vision ملاتړ کوي.</td></tr><tr><td>Copy results</td><td>له processing وروسته recognized text copy کړئ.</td></tr><tr><td>Export files</td><td><code>Markdown</code>، <code>PDF</code> او <code>Word</code> export کړئ.</td></tr><tr><td>Batch packaging</td><td>د څو files له recognize وروسته results د package په توګه download کړئ.</td></tr></tbody></table><h2 id="لومړی-ocr-services-تنظیم-کړئ" tabindex="-1">لومړی OCR Services تنظیم کړئ <a class="header-anchor" href="#لومړی-ocr-services-تنظیم-کړئ" aria-label="Permalink to &quot;لومړی OCR Services تنظیم کړئ&quot;">​</a></h2><p>دا پرانیزئ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+e+'" alt="IP geolocation and OCR" loading="lazy"></p><p>د هغو services credentials ډک کړئ چې کارول یې غواړئ:</p><table tabindex="0"><thead><tr><th>Service</th><th>څه ولیکئ</th><th>Best For</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>لومړی انتخاب یې سپارښتنه کېږي. د documents، images، tables او mixed layouts لپاره ښه دی.</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> او <code>Azure Vision API Key</code></td><td>که Microsoft cloud services کاروئ، ګټور دی.</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>. Service account <code>JSON</code> یوازې د quota query لپاره کارېږي.</td><td>که Google Cloud services کاروئ، ګټور دی.</td></tr></tbody></table><p>له credentials ډکولو وروسته save وکړئ.</p><p>د لومړنۍ ازموینې لپاره یوازې یو service تنظیمولای شئ. درې واړه اړین نه دي.</p><h2 id="google-vision-setup" tabindex="-1">Google Vision Setup <a class="header-anchor" href="#google-vision-setup" aria-label="Permalink to &quot;Google Vision Setup&quot;">​</a></h2><p>Google setup دوه برخې لري:</p><table tabindex="0"><thead><tr><th>Goal</th><th>Requirement</th></tr></thead><tbody><tr><td>OCR کارول</td><td><code>Cloud Vision API</code> enable کړئ، بیا <code>API Key</code> جوړ کړئ.</td></tr><tr><td>usage query</td><td>service account جوړ کړئ، <code>Monitoring Viewer</code> ورکړئ، بیا service account <code>JSON</code> download کړئ.</td></tr></tbody></table><p><img src="'+i+'" alt="Google API key and service account" loading="lazy"></p><h3 id="google-د-ocr-لپاره-وکاروئ" tabindex="-1">Google د OCR لپاره وکاروئ <a class="header-anchor" href="#google-د-ocr-لپاره-وکاروئ" aria-label="Permalink to &quot;Google د OCR لپاره وکاروئ&quot;">​</a></h3><ol><li>Google Cloud Console پرانیزئ.</li><li><code>APIs &amp; Services</code> ته لاړ شئ.</li><li><code>Library</code> پرانیزئ، <code>Cloud Vision API</code> ولټوئ او enable یې کړئ.</li><li>بېرته <code>Credentials</code> ته راشئ.</li><li><code>API Key</code> جوړ کړئ.</li><li>API Key پرانیزئ او copy یې کړئ.</li><li>په ImgBed کې یې <code>Google Vision API Key</code> ته paste کړئ.</li><li>save کړئ.</li></ol><p>بیا د OCR dialog کې Google Vision ټاکلای شئ.</p><h3 id="د-google-usage-query" tabindex="-1">د Google Usage Query <a class="header-anchor" href="#د-google-usage-query" aria-label="Permalink to &quot;د Google Usage Query&quot;">​</a></h3><p>Quota query د recognition لپاره اړینه نه ده.</p><p>دا یوازې ښيي چې په تېرو 30 ورځو کې شاوخوا څو Google Vision calls کارول شوي دي.</p><ol><li>په Google Cloud Console کې <code>IAM &amp; Admin</code> پرانیزئ.</li><li><code>Service Accounts</code> پرانیزئ.</li><li>service account جوړ کړئ، لکه <code>vision-monitor</code>.</li><li><code>Monitoring Viewer</code> role ورکړئ.</li><li>د service account details پرانیزئ او key جوړ کړئ.</li><li><code>JSON</code> وټاکئ.</li><li>generated JSON file download کړئ.</li><li>بېرته ImgBed ته راشئ او د service account <code>JSON</code> لاندې یې import کړئ (اختیاري).</li><li>د import له بریا وروسته quota query کلیک کړئ.</li></ol><p>له import وروسته، ImgBed هغه project name ښيي چې service account پورې تړاو لري. د usage query پر وخت، ImgBed Google monitoring data لولي او د دې میاشت call count ښيي.</p><p>په لنډه توګه:</p><table tabindex="0"><thead><tr><th>Item</th><th>موخه</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>OCR recognition اجرا کوي.</td></tr><tr><td>Service account <code>JSON</code></td><td>ګوري چې څو Google Vision calls کارول شوي دي.</td></tr><tr><td><code>Monitoring Viewer</code> role</td><td>service account ته د usage data د لوستلو اجازه ورکوي.</td></tr></tbody></table><h2 id="baidu-paddleocr-token-اخیستل" tabindex="-1">Baidu PaddleOCR Token اخیستل <a class="header-anchor" href="#baidu-paddleocr-token-اخیستل" aria-label="Permalink to &quot;Baidu PaddleOCR Token اخیستل&quot;">​</a></h2><p>Baidu PaddleOCR access token غواړي.</p><p><img src="'+o+'" alt="Get PaddleOCR token" loading="lazy"></p><p>د Baidu PaddleOCR page کې د <code>API</code> call window پرانیزئ، د token اخیستلو لپاره کلیک وکړئ، بیا یې copy کړئ.</p><p>بېرته ImgBed ته راشئ، په <code>PaddleOCR Token</code> کې یې paste او save کړئ.</p><h2 id="recognition-پیلول" tabindex="-1">Recognition پیلول <a class="header-anchor" href="#recognition-پیلول" aria-label="Permalink to &quot;Recognition پیلول&quot;">​</a></h2><p>په File Management کې image یا document screenshot وټاکئ او <code>OCR</code> کلیک کړئ.</p><p><img src="'+a+'" alt="OCR recognition" loading="lazy"></p><p>په dialog کې recognition service او model وټاکئ.</p><p>عام PaddleOCR model choices:</p><table tabindex="0"><thead><tr><th>Model</th><th>Best For</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>سپارښتل شوی default. د documents، tables، formulas، stamps او mixed layouts لپاره ښه دی.</td></tr><tr><td><code>PP-OCRv5</code></td><td>ساده images، عادي text او lightweight recognition.</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>multilingual، complex images او chart-like content.</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>ډېر complex document pages او layout recovery.</td></tr></tbody></table><p>که ډاډه نه یاست، له <code>PP-StructureV3</code> څخه پیل وکړئ.</p><h2 id="advanced-options" tabindex="-1">Advanced Options <a class="header-anchor" href="#advanced-options" aria-label="Permalink to &quot;Advanced Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>تشریح</th></tr></thead><tbody><tr><td>Orientation correction</td><td>کله وکاروئ چې image rotated یا skewed وي.</td></tr><tr><td>Document flattening</td><td>د curvature یا tilt لرونکو photographed documents لپاره.</td></tr><tr><td>Layout detection</td><td>کله چې headings، paragraphs، tables او image structure ساتل غواړئ.</td></tr><tr><td>Chart recognition</td><td>کله چې image charts یا complex structures ولري.</td></tr><tr><td>Beautify <code>Markdown</code></td><td>exported Markdown لوستل اسانه کوي.</td></tr></tbody></table><p>د عادي screenshots لپاره options کم وساتئ. د document scans لپاره نور document-related options فعال کړئ.</p><h2 id="results-لیدل" tabindex="-1">Results لیدل <a class="header-anchor" href="#results-لیدل" aria-label="Permalink to &quot;Results لیدل&quot;">​</a></h2><p>له recognition وروسته dialog result ښيي.</p><p>مستقیم یې copy کولای شئ یا export formats ټاکلای شئ.</p><p><img src="'+d+'" alt="PDF recognition" loading="lazy"></p><p>د document pages لپاره، exported <code>PDF</code> د page appearance ساتلی شي او text searchable پرېږدي. دا د scans archive کولو او وروسته content موندلو لپاره ګټور دی.</p><h2 id="export-format-ټاکل" tabindex="-1">Export Format ټاکل <a class="header-anchor" href="#export-format-ټاکل" aria-label="Permalink to &quot;Export Format ټاکل&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Best For</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>notes، documentation systems او وروسته editing.</td></tr><tr><td><code>PDF (.pdf)</code></td><td>د page appearance او scanned document results ساتل.</td></tr><tr><td><code>Word (.docx)</code></td><td>layout editing ته دوام، text modification او نورو ته handoff.</td></tr><tr><td>Export all</td><td>څو formats او original image خوندي کوي، د مهمو archives لپاره مناسب دی.</td></tr></tbody></table><p>که یوازې text ته اړتیا لرئ، Markdown export کړئ.</p><p>که page appearance ته اړتیا لرئ، PDF یا Word وکاروئ.</p><h2 id="word-output" tabindex="-1">Word Output <a class="header-anchor" href="#word-output" aria-label="Permalink to &quot;Word Output&quot;">​</a></h2><p>Exported Word documents د office software له لارې پرانیستل او edit کېدای شي.</p><p><img src="'+r+`" alt="Word result" loading="lazy"></p><p>ځینې documents په Word output کې recognized images، headings او paragraphs لري.</p><p>Recognition quality د original image clarity، model choice او document complexity پورې تړلې ده.</p><h2 id="د-ocr-لپاره-غوره-file-types" tabindex="-1">د OCR لپاره غوره File Types <a class="header-anchor" href="#د-ocr-لپاره-غوره-file-types" aria-label="Permalink to &quot;د OCR لپاره غوره File Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File Type</th><th>سپارښتنه</th></tr></thead><tbody><tr><td>Clear screenshots</td><td>مستقیم recognize کړئ.</td></tr><tr><td>Scans</td><td><code>PP-StructureV3</code> ته ترجیح ورکړئ.</td></tr><tr><td>Photographed documents</td><td>orientation correction او document flattening فعال کړئ.</td></tr><tr><td>Tables, formulas, stamps</td><td>structured models ته ترجیح ورکړئ.</td></tr><tr><td>Simple short text images</td><td><code>PP-OCRv5</code> عموما بس وي.</td></tr></tbody></table><p>روښانه images چې text یې مستقیم وي، عموما غوره results ورکوي.</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>معنا</th></tr></thead><tbody><tr><td>Recognition fails</td><td>وګورئ service token یا key save شوی دی.</td></tr><tr><td>Recognition is slow</td><td>complex documents او لوی images ډېر وخت نیسي.</td></tr><tr><td>Table incomplete دی</td><td>structured model وازمویئ.</td></tr><tr><td>Text mistakes لري</td><td>blur، glare او skew recognition errors زیاتوي. روښانه image وازمویئ.</td></tr><tr><td>Word output ډېر images لري</td><td>structured models ښايي ځینې recognized images وساتي. دا عادي ده.</td></tr></tbody></table><h3 id="google-quota-query-ناکامېږي" tabindex="-1">Google Quota Query ناکامېږي <a class="header-anchor" href="#google-quota-query-ناکامېږي" aria-label="Permalink to &quot;Google Quota Query ناکامېږي&quot;">​</a></h3><p>وګورئ:</p><ol><li>Service account <code>JSON</code> import شوی دی.</li><li>service account د <code>Monitoring Viewer</code> role لري.</li><li><code>Cloud Vision API</code> د project لپاره enabled دی.</li></ol><p>که یوازې OCR ته اړتیا لرئ او usage query نه غواړئ، service account JSON ignore کولای شئ او یوازې <code>Google Vision API Key</code> ډک کړئ.</p><h2 id="چټک-بهیر" tabindex="-1">چټک بهیر <a class="header-anchor" href="#چټک-بهیر" aria-label="Permalink to &quot;چټک بهیر&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open System Settings</span></span>
<span class="line"><span>-&gt; Open Other Settings</span></span>
<span class="line"><span>-&gt; Fill OCR service credentials</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; Return to File Management</span></span>
<span class="line"><span>-&gt; Select a file and click OCR</span></span>
<span class="line"><span>-&gt; Choose a model</span></span>
<span class="line"><span>-&gt; Wait for recognition</span></span>
<span class="line"><span>-&gt; Copy results or export Markdown / PDF / Word</span></span></code></pre></div>`,67)])])}const O=s(p,[["render",u]]);export{v as __pageData,O as default};
